  const { client } = trpc.useContext();
  const [message, setMessage] = useState("");
  const [response, setResponse] = useState("");
  const [isStreaming, setIsStreaming] = useState(false);

  const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    if (!message.trim() || isStreaming) {
      return;
    }

    setIsStreaming(true);
    setResponse("");

    try {
      const stream = await client.chat.query(message);
      let nextResponse = "";
      for await (const chunk of stream) {
        nextResponse += chunk;
        setResponse(nextResponse);
      }
    } finally {
      setIsStreaming(false);
    }
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-zinc-50 px-6 py-16 text-zinc-900">
      <main className="flex w-full max-w-2xl flex-col gap-8 rounded-3xl bg-white p-8 shadow-xl">
        <header className="space-y-2">
          <h1 className="text-3xl font-semibold">tRPC v11 Streaming Chat</h1>
          <p className="text-sm text-zinc-500">
            Type a message to see the server stream it back character by
            character.
          </p>
        </header>
        <form className="flex flex-col gap-4" onSubmit={handleSubmit}>
          <label className="flex flex-col gap-2 text-sm font-medium" htmlFor="chat-input">
            Message
            <input
              id="chat-input"
              name="message"
              type="text"
              value={message}
              onChange={(event) => setMessage(event.target.value)}
              placeholder="Say hello..."
              className="rounded-xl border border-zinc-200 px-4 py-3 text-base shadow-sm focus:border-zinc-400 focus:outline-none"
            />
          </label>
          <button
            id="chat-submit"
            type="submit"
            disabled={isStreaming}
            className="rounded-xl bg-black px-4 py-3 text-sm font-semibold text-white transition disabled:cursor-not-allowed disabled:bg-zinc-400"
          >
            {isStreaming ? "Streaming..." : "Send"}
          </button>
        </form>
        <section className="space-y-2">
          <h2 className="text-sm font-semibold uppercase tracking-wide text-zinc-500">
            Response
          </h2>
          <div
            id="chat-response"
            className="min-h-[96px] rounded-2xl border border-zinc-200 bg-zinc-50 px-4 py-3 text-base text-zinc-700"
          >
            {response || "Awaiting response..."}
          </div>
        </section>
      </main>

